+import { object } from "@optique/core/constructs";
+import { withDefault } from "@optique/core/modifiers";
+import { parseSync } from "@optique/core/parser";
+import { optionalWhen, option, requiredWhen } from "@optique/core/primitives";
+import { string } from "@optique/core/valueparser";
+import assert from "node:assert/strict";
+import { describe, it } from "node:test";
+
+describe("conditional options", () => {
+  it("maps CLI flag dependencies through wrapped parsers", () => {
+    const parser = object({
+      enabled: option("--enabled"),
+      token: withDefault(
+        requiredWhen("--enabled", "--token", string()),
+        "default",
+      ),
+    });
+
+    const result = parseSync(parser, ["--token", "secret"]);
+    assert.ok(!result.success);
+    if (!result.success) {
+      assert.match(String(result.error), /requires option/);
+      assert.match(String(result.error), /--enabled/);
+    }
+  });
+
+  it("accepts object keys and compound conditions", () => {
+    const parser = object({
+      alpha: option("--alpha"),
+      beta: option("--beta"),
+      target: requiredWhen(
+        { allOf: [{ option: "alpha" }, "--beta"] },
+        "--target",
+        string(),
+      ),
+    });
+    const result = parseSync(parser, [
+      "--alpha",
+      "--beta",
+      "--target",
+      "value",
+    ]);
+    assert.ok(result.success);
+  });
+
+  it("hides unsatisfied optional dependencies from documentation", () => {
+    const parser = object({
+      enabled: option("--enabled"),
+      extra: optionalWhen("enabled", "--extra", string()),
+    });
+    const fragments = parser.getDocFragments({
+      kind: "available",
+      state: parser.initialState,
+    }).fragments;
+    assert.ok(!JSON.stringify(fragments).includes("--extra"));
+  });
+});
