/** A condition accepted by the conditional option helpers. */
export type ConditionalOptionCondition = string | OptionDependencyCondition |
  OptionDependency;

function conditionalDependency(
  condition: ConditionalOptionCondition,
  required: boolean,
): OptionDependency {
  if (typeof condition === "string") return { option: condition, required };
  return { ...condition, required: condition.required ?? required };
}

function optionNamesFromSpec(flagSpec: OptionName | readonly OptionName[]): OptionName[] {
  return typeof flagSpec === "string" ? [flagSpec] : [...flagSpec];
}

/** Creates an option that requires its dependency to be satisfied when used. */
export function requiredWhen<M extends Mode, T>(
  condition: ConditionalOptionCondition,
  flagSpec: OptionName | readonly OptionName[],
  valueParser: ValueParser<M, T>,
): Parser<M, T, ValueParserResult<T> | undefined>;
export function requiredWhen(
  condition: ConditionalOptionCondition,
  flagSpec: OptionName | readonly OptionName[],
): Parser<"sync", boolean, ValueParserResult<boolean> | undefined>;
export function requiredWhen<M extends Mode, T>(
  condition: ConditionalOptionCondition,
  flagSpec: OptionName | readonly OptionName[],
  valueParser?: ValueParser<M, T>,
): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
  const names = optionNamesFromSpec(flagSpec);
  return valueParser == null
    ? option(...names, { dependsOn: conditionalDependency(condition, true) })
    : option(...names, valueParser, {
      dependsOn: conditionalDependency(condition, true),
    });
}

/** Creates an option that is shown only when its dependency is satisfied. */
export function optionalWhen<M extends Mode, T>(
  condition: ConditionalOptionCondition,
  flagSpec: OptionName | readonly OptionName[],
  valueParser: ValueParser<M, T>,
): Parser<M, T, ValueParserResult<T> | undefined>;
export function optionalWhen(
  condition: ConditionalOptionCondition,
  flagSpec: OptionName | readonly OptionName[],
): Parser<"sync", boolean, ValueParserResult<boolean> | undefined>;
export function optionalWhen<M extends Mode, T>(
  condition: ConditionalOptionCondition,
  flagSpec: OptionName | readonly OptionName[],
  valueParser?: ValueParser<M, T>,
): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
  const names = optionNamesFromSpec(flagSpec);
  return valueParser == null
    ? option(...names, { dependsOn: conditionalDependency(condition, false) })
    : option(...names, valueParser, {
      dependsOn: conditionalDependency(condition, false),
